module RefModule(
    input clk,
    input we,
    input [1:0] write_addr,
    input [1:0] read_addr,
    input [7:0] data_in,
    output reg [7:0] data_out
);
    reg [7:0] unused_registers [3:0];

    always @(posedge clk) begin
        if (we)
            unused_registers[write_addr] <= data_in;
    end

    always @(*) begin
        data_out = unused_registers[read_addr];
    end
endmodule
